// Función para detectar metadatos de archivo en respuesta de agente
function detectFileMetadata(agentResponse) {
    const metadata = {
        hasFileOperation: false,
        files: [],
        errors: []
    };

    try {
        // Buscar JSON al final de la respuesta
        const jsonMatch = agentResponse.match(/\{[^{}]*"archivos_modificados"[^{}]*\}$/);
        if (jsonMatch) {
            const jsonData = JSON.parse(jsonMatch[0]);
            if (jsonData.archivos_modificados && Array.isArray(jsonData.archivos_modificados)) {
                metadata.hasFileOperation = true;
                metadata.files = jsonData.archivos_modificados.map(file => ({
                    path: file,
                    type: 'modified',
                    detected: true
                }));
            }
        }

        // Buscar patrones de archivo_destino y contenido
        const fileDestPattern = /"archivo_destino"\s*:\s*"([^"]+)"/g;
        const contentPattern = /"contenido"\s*:\s*"([^"]+)"/g;

        let fileMatch;
        const detectedFiles = new Map();

        // Extraer archivos destino
        while ((fileMatch = fileDestPattern.exec(agentResponse)) !== null) {
            const filePath = fileMatch[1];
            detectedFiles.set(filePath, { path: filePath, content: null, type: 'create' });
        }

        // Extraer contenido (buscar el más cercano a cada archivo)
        for (const [filePath, fileData] of detectedFiles) {
            const fileIndex = agentResponse.indexOf(`"archivo_destino":"${filePath}"`);
            const contentAfterFile = agentResponse.substring(fileIndex);
            const contentMatch = contentAfterFile.match(/"contenido"\s*:\s*"([^"]+)"/);

            if (contentMatch) {
                fileData.content = contentMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
                metadata.hasFileOperation = true;

                // Evitar duplicados
                const exists = metadata.files.some(f => f.path === filePath);
                if (!exists) {
                    metadata.files.push(fileData);
                }
            }
        }

    } catch (error) {
        metadata.errors.push(`Error parsing metadata: ${error.message}`);
    }

    return metadata;
}

// Función para validar rutas de escritura
function validateWritePath(filePath) {
    const resolvedPath = path.resolve(filePath);

    // Verificar que esté dentro de rutas permitidas
    const isAllowed = ALLOWED_WRITE_PATHS.some(allowedPath => {
        const resolvedAllowed = path.resolve(allowedPath);
        return resolvedPath.startsWith(resolvedAllowed);
    });

    if (!isAllowed) {
        throw new Error(`Ruta no permitida para escritura: ${filePath}`);
    }

    // Verificar que no contenga caracteres peligrosos
    if (filePath.includes('..') || filePath.includes('~') || filePath.match(/[<>:"|?*]/)) {
        throw new Error(`Ruta contiene caracteres peligrosos: ${filePath}`);
    }

    // Verificar extensión de archivo
    const allowedExtensions = ['.js', '.json', '.html', '.css', '.md', '.txt', '.sql', '.env'];
    const extension = path.extname(filePath).toLowerCase();

    if (!allowedExtensions.includes(extension)) {
        throw new Error(`Extensión de archivo no permitida: ${extension}`);
    }

    return resolvedPath;
}

// Función para escribir archivo desde respuesta de agente
async function writeFileFromAgent(filePath, content, options = {}) {
    const { 
        createBackup = true, 
        validateContent = true,
        agentName = 'unknown' 
    } = options;

    try {
        // Validar ruta
        const validatedPath = validateWritePath(filePath);

        // Validar contenido si es requerido
        if (validateContent && (!content || typeof content !== 'string')) {
            throw new Error('Contenido inválido o vacío');
        }

        // Crear backup si el archivo existe
        if (createBackup) {
            try {
                await fs.access(validatedPath);
                const backupPath = `${validatedPath}.backup.${Date.now()}`;
                await fs.copyFile(validatedPath, backupPath);
                console.log(`✓ Backup creado: ${backupPath}`);
            } catch (error) {
                // Archivo no existe, no crear backup
            }
        }

        // Crear directorio si no existe
        const directory = path.dirname(validatedPath);
        await fs.mkdir(directory, { recursive: true });

        // Escribir archivo
        await fs.writeFile(validatedPath, content, 'utf8');

        const result = {
            success: true,
            path: validatedPath,
            size: content.length,
            agent: agentName,
            timestamp: new Date().toISOString()
        };

        console.log(`✓ Archivo escrito por ${agentName}: ${validatedPath} (${content.length} bytes)`);
        return result;

    } catch (error) {
        const errorResult = {
            success: false,
            path: filePath,
            error: error.message,
            agent: agentName,
            timestamp: new Date().toISOString()
        };

        console.error(`✗ Error escribiendo archivo ${filePath} por ${agentName}: ${error.message}`);
        return errorResult;
    }
}

// Función mejorada para procesar respuesta de agente
async function processAgentResponse(agentName, response, originalTask) {
    const metadata = detectFileMetadata(response);
    const results = {
        agent: agentName,
        task: originalTask,
        response: response,
        fileOperations: [],
        errors: [],
        timestamp: new Date().toISOString()
    };

    if (metadata.hasFileOperation) {
        console.log(`📁 ${agentName} detectó ${metadata.files.length} operaciones de archivo`);

        for (const fileOp of metadata.files) {
            if (fileOp.content) {
                const writeResult = await writeFileFromAgent(
                    fileOp.path, 
                    fileOp.content, 
                    { agentName }
                );
                results.fileOperations.push(writeResult);

                if (!writeResult.success) {
                    results.errors.push(writeResult.error);
                }
            }
        }
    }

    // Agregar errores de metadata
    results.errors.push(...metadata.errors);

    return results;
}

