function validateFilePath(filePath) {
    // Resolver path absoluto
    const resolvedPath = path.resolve(filePath);

    // Verificar que esté dentro del directorio permitido
    if (!resolvedPath.startsWith(ALLOWED_BASE_PATH)) {
        throw new Error(`Ruta no permitida: ${resolvedPath}. Solo se permite escribir en ${ALLOWED_BASE_PATH}`);
    }

    // Verificar caracteres peligrosos
    if (DANGEROUS_CHARS.test(filePath)) {
        throw new Error(`Caracteres no permitidos en la ruta: ${filePath}`);
    }

    return resolvedPath;
}

